  7→export function createProject(name = 'Untitled Project') {
  8→  return {
  9→    id: generateId('proj'),
 10→    name,
 11→    address: '',
 12→    documentDefaults: {
 13→      drawnBy: '',
 14→      checkedBy: '',
 15→    },
 16→    createdAt: new Date().toISOString(),
 17→    updatedAt: new Date().toISOString(),
 18→    floors: [createFloor('Ground Floor', 0, { elevation: 0, floorToFloorHeight: WALL_HEIGHT })],
 19→    roofSystem: null,
 20→    trussSystems: [],
 21→    sheets: [],
 22→    phases: [],
 23→    version: CURRENT_PROJECT_VERSION,
 24→  };
 25→}
