 27→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 28→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 29→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 30→
 31→  return {
 32→    id: generateId('floor'),
 33→    name,
 34→    levelIndex,
 35→    elevation,
 36→    floorToFloorHeight,
 37→    walls: [],
 38→    rooms: [],
 39→    doors: [],
 40→    windows: [],
 41→    columns: [],
 42→    beams: [],
 43→    stairs: [],
 44→    landings: [],
 45→    fixtures: [],
 46→    annotations: [],
 47→    annotationSettings: createAnnotationSettings(),
 48→    slabs: [],
 49→    sectionCuts: [],
 50→    railings: [],
 51→  };
 52→}
 53→
 54→export function nextSectionLabel(existingCuts = []) {
 55→  const usedLetters = new Set(
 56→    existingCuts
 57→      .map(c => {
 58→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 59→        return match ? match[1] : null;
 60→      })
 61→      .filter(Boolean)
 62→  );
 63→  for (let i = 0; i < 26; i++) {
 64→    const letter = String.fromCharCode(65 + i);
 65→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 66→  }
 67→  return `Section ${existingCuts.length + 1}`;
 68→}
