 50→export default function Toolbar({
 51→  onNew,
 52→  onSave,
 53→  onLoad,
 54→  isSidebarCollapsed,
 55→  isPropertiesCollapsed,
 56→  onToggleSidebar,
 57→  onToggleProperties,
 58→}) {
 59→  const {
 60→    activeTool,
 61→    showGrid,
 62→    snapEnabled,
 63→    activeFloorId,
 64→    viewMode,
 65→    workspaceMode,
 66→    modelTarget,
 67→    toolState,
 68→    activePhaseId,
 69→    selectedId,
 70→    selectedType,
 71→    dispatch: editorDispatch,
 72→  } = useEditor();
 73→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 74→  const {
 75→    canCopySelection,
 76→    canPaste,
 77→    copySelection,
 78→    cutSelection,
 79→    beginPaste,
 80→  } = usePlanClipboardController();
 81→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'floor';
 82→  const isRoofPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'roof';
 83→  const isTrussPlanView = workspaceMode === 'model' && viewMode === 'plan' && modelTarget === 'truss';
 84→
 85→  const fixtureItems = [
 86→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 87→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 88→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 89→    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 90→    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 91→    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 92→    { fixtureType: FIXTURE_TYPES.BED, label: 'Bed', Icon: BedIcon },
 93→  ];
 94→
 95→  const setTool = (tool) => {
 96→    editorDispatch({ type: 'SET_TOOL', tool });
 97→
 98→    if (tool !== TOOLS.TRUSS_DRAW || modelTarget !== 'truss') return;
 99→
100→    const targetTrussSystem = selectedType === 'trussSystem'
101→      ? (project.trussSystems || []).find((entry) => entry.id === selectedId) || null
102→      : selectedType === 'trussInstance'
103→        ? (project.trussSystems || []).find((entry) => (
104→            (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
105→          )) || null
106→        : null;
107→    const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
108→      ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
109→      : null;
110→    const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
111→      ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
112→      : null;
113→
114→    editorDispatch({
115→      type: 'UPDATE_TOOL_STATE',
116→      payload: {
117→        targetTrussSystemId: targetTrussSystem?.id || null,
118→        trussTypeId: selectedTrussInstance?.trussTypeId
119→          || lastSystemInstance?.trussTypeId
120→          || null,
121→        trussMaterial: selectedTrussInstance?.material
122→          || lastSystemInstance?.material
123→          || null,
124→      },
125→    });
126→  };
127→  const roofToolItems = [
128→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
129→    { tool: TOOLS.ROOF_PARAPET, label: 'Parapet', shortcut: 'P', Icon: ParapetIcon },
130→    { tool: TOOLS.ROOF_DRAIN, label: 'Drain', shortcut: 'G', Icon: DrainIcon },
131→    { tool: TOOLS.ROOF_OPENING, label: 'Opening', shortcut: 'O', Icon: OpeningIcon },
132→  ];
133→  const trussToolItems = [
134→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V', Icon: SelectIcon },
135→    { tool: TOOLS.TRUSS_DRAW, label: 'Draw Truss', shortcut: 'T', Icon: TrussDrawIcon },
136→  ];
