226→            onClick={handleRedo}
227→            disabled={!canRedo}
228→            aria-label="Redo"
229→          >
230→            <RedoIcon className={styles.icon} />
231→          </button>
232→        </Tooltip>
233→        <Tooltip label="Save" shortcut="Ctrl+S">
234→          <button
235→            className={styles.saveBtn}
236→            onClick={onSave}
237→            data-dirty={isDirty}
238→            aria-label="Save"
239→          >
240→            <SaveIcon className={styles.icon} />
241→          </button>
242→        </Tooltip>
243→        <div className={styles.divider} />
244→        <Tooltip label="Load Project">
245→          <button className={styles.btn} onClick={onLoad} aria-label="Load Project">
246→            <LoadIcon className={styles.icon} />
247→          </button>
248→        </Tooltip>
249→        <Tooltip label="Copy" shortcut="Ctrl+C">
250→          <button
251→            className={styles.btn}
252→            onClick={copySelection}
253→            disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
254→            aria-label="Copy"
255→          >
256→            <CopyIcon className={styles.icon} />
257→          </button>
258→        </Tooltip>
259→        <Tooltip label="Cut" shortcut="Ctrl+X">
260→          <button
261→            className={styles.btn}
262→            onClick={cutSelection}
263→            disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
264→            aria-label="Cut"
265→          >
266→            <CutIcon className={styles.icon} />
267→          </button>
268→        </Tooltip>
269→        <Tooltip label="Paste" shortcut="Ctrl+V">
270→          <button
271→            className={styles.btn}
272→            onClick={() => beginPaste()}
273→            disabled={!canPaste || modelTarget !== 'floor' || workspaceMode !== 'model'}
274→            aria-label="Paste"
275→          >
276→            <PasteIcon className={styles.icon} />
277→          </button>
278→        </Tooltip>
279→      </div>
280→
281→      <div className={styles.segmentedGroup}>
282→        <button
283→          className={workspaceMode === 'model' && modelTarget === 'floor' ? styles.segmentedBtnActive : styles.segmentedBtn}
284→          onClick={() => {
