344→export default function FloorplanWorkspace({ initialProject, isPlayground = false }) {
345→  return (
346→    <div className="editorRoot">
347→      <ProjectProvider initialProject={initialProject}>
348→        <ClipboardProvider>
349→          <FloorplanInner isPlayground={isPlayground} />
350→        </ClipboardProvider>
