import { generateId } from '@/domain/ids';

export function createSketchProject(name = 'Untitled Sketch') {
  return {
    id: generateId('sketch'),
    name,
    canvasWidth: 297000,  // A4 landscape in mm
    canvasHeight: 210000,
    layers: [createLayer('Layer 1')],
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}

export function createLayer(name = 'Layer') {
  return {
    id: generateId('layer'),
    name,
    visible: true,
    locked: false,
    shapes: [],
  };
}

export function createShape(type, props = {}) {
  return {
    id: generateId('shape'),
    type, // 'rect', 'ellipse', 'line', 'path'
    layerId: props.layerId || null,
    x: props.x ?? 0,
    y: props.y ?? 0,
    width: props.width ?? 0,
    height: props.height ?? 0,
    points: props.points ?? [],
    fill: props.fill ?? 'none',
    stroke: props.stroke ?? '#1E2433',
    strokeWidth: props.strokeWidth ?? 2,
    rotation: props.rotation ?? 0,
  };
}

export const SKETCH_TOOLS = {
  SELECT: 'select',
  RECTANGLE: 'rectangle',
  ELLIPSE: 'ellipse',
  LINE: 'line',
  PEN: 'pen',
};

export const DEFAULT_SKETCH_ZOOM = 0.15;
export const DEFAULT_CANVAS_WIDTH = 297000;
export const DEFAULT_CANVAS_HEIGHT = 210000;

export const SKETCH_MIN_ZOOM = 0.02;
export const SKETCH_MAX_ZOOM = 3.0;
export const SKETCH_ZOOM_FACTOR = 1.1;

export const SKETCH_GRID_MINOR = 50;   // mm
export const SKETCH_GRID_MAJOR = 1000; // mm

export const SKETCH_SNAP_DISTANCE_PX = 8;

export { SKETCH_TOOLS } from '../domain/defaults';

export const SKETCH_TOOL_SHORTCUTS = {
  v: 'select',
  r: 'rectangle',
  e: 'ellipse',
  l: 'line',
  p: 'pen',
};

import { createContext, useContext, useReducer } from 'react';
import { createSketchProject, createLayer } from '../domain/sketchModels';

const SketchContext = createContext(null);
const HISTORY_LIMIT = 80;

function snapshotSketch(sketchProject) {
  return JSON.stringify(sketchProject);
}

function applyUpdate(state, nextProject, recordHistory = true) {
  const nextSnapshot = snapshotSketch(nextProject);
  const history = recordHistory
    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
    : state.history;

  return {
    ...state,
    history,
    future: recordHistory ? [] : state.future,
    project: nextProject,
    isDirty: nextSnapshot !== state.savedSnapshot,
  };
}

function updateLayer(state, layerId, updater) {
  const nextLayers = state.project.layers.map((layer) =>
    layer.id === layerId ? updater(layer) : layer
  );
  return applyUpdate(state, {
    ...state.project,
    updatedAt: new Date().toISOString(),
    layers: nextLayers,
  });
}

function sketchReducer(state, action) {
  switch (action.type) {
    case 'SKETCH_NEW': {
      const newProject = action.project || createSketchProject();
      return {
        project: newProject,
        isDirty: false,
        savedSnapshot: snapshotSketch(newProject),
        history: [],
        future: [],
      };
    }

    case 'SKETCH_LOAD': {
      const loaded = action.project;
      return {
        project: loaded,
        isDirty: false,
        savedSnapshot: snapshotSketch(loaded),
        history: [],
        future: [],
      };
    }

    case 'LAYER_ADD': {
      const newLayer = action.layer || createLayer();
      return applyUpdate(state, {
        ...state.project,
        updatedAt: new Date().toISOString(),
        layers: [...state.project.layers, newLayer],
      });
    }

    case 'LAYER_UPDATE':
      return applyUpdate(state, {
        ...state.project,
        updatedAt: new Date().toISOString(),
        layers: state.project.layers.map((layer) =>
          layer.id === action.layer.id ? { ...layer, ...action.layer } : layer
        ),
      });

    case 'LAYER_DELETE': {
      if (state.project.layers.length <= 1) return state;
      return applyUpdate(state, {
        ...state.project,
        updatedAt: new Date().toISOString(),
        layers: state.project.layers.filter((layer) => layer.id !== action.layerId),
      });
    }

    case 'LAYER_REORDER':
      return applyUpdate(state, {
        ...state.project,
        updatedAt: new Date().toISOString(),
        layers: action.layers,
      });

    case 'SHAPE_ADD':
      return updateLayer(state, action.layerId, (layer) => ({
        ...layer,
        shapes: [...layer.shapes, action.shape],
      }));

    case 'SHAPE_UPDATE':
      return updateLayer(state, action.layerId, (layer) => ({
        ...layer,
        shapes: layer.shapes.map((shape) =>
          shape.id === action.shape.id ? { ...shape, ...action.shape } : shape
        ),
      }));

    case 'SHAPE_DELETE':
      return updateLayer(state, action.layerId, (layer) => ({
        ...layer,
        shapes: layer.shapes.filter((shape) => shape.id !== action.shapeId),
      }));

    case 'UNDO': {
      if (state.history.length === 0) return state;
      const previous = state.history[state.history.length - 1];
      return {
        ...state,
        project: previous,
        history: state.history.slice(0, -1),
        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
      };
    }

    case 'REDO': {
      if (state.future.length === 0) return state;
      const next = state.future[0];
      return {
        ...state,
        project: next,
        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
        future: state.future.slice(1),
        isDirty: snapshotSketch(next) !== state.savedSnapshot,
      };
    }

    case 'MARK_SAVED':
      return {
        ...state,
        isDirty: false,
        savedSnapshot: snapshotSketch(state.project),
      };

    default:
      return state;
  }
}

function createInitialState(project) {
  return {
    project,
    isDirty: false,
    savedSnapshot: snapshotSketch(project),
    history: [],
    future: [],
  };
}

export function SketchProvider({ children, initialProject }) {
  const [state, dispatch] = useReducer(
    sketchReducer,
    initialProject || createSketchProject(),
    createInitialState
  );

  return (
    <SketchContext.Provider value={{ state, dispatch }}>
      {children}
    </SketchContext.Provider>
  );
}

export function useSketch() {
  const ctx = useContext(SketchContext);
  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
  const { state, dispatch } = ctx;

  return {
    project: state.project,
    isDirty: state.isDirty,
    canUndo: state.history.length > 0,
    canRedo: state.future.length > 0,
    dispatch,
    getLayer: (layerId) => state.project.layers.find((l) => l.id === layerId) || null,
  };
}

import { createContext, useContext, useReducer } from 'react';
import { SKETCH_TOOLS, DEFAULT_SKETCH_ZOOM } from '../domain/defaults';

const SketchEditorContext = createContext(null);

function sketchEditorReducer(state, action) {
  switch (action.type) {
    case 'SET_TOOL':
      return {
        ...state,
        activeTool: action.tool,
        toolState: {},
        selectedId: null,
        selectedType: null,
      };

    case 'SELECT_OBJECT':
      return {
        ...state,
        selectedId: action.id,
        selectedType: action.objectType,
      };

    case 'DESELECT':
      return {
        ...state,
        selectedId: null,
        selectedType: null,
      };

    case 'UPDATE_TOOL_STATE':
      return {
        ...state,
        toolState: { ...state.toolState, ...action.payload },
      };

    case 'SET_VIEWPORT':
      return {
        ...state,
        viewport: { ...action.viewport },
      };

    case 'PAN':
      return {
        ...state,
        viewport: {
          ...state.viewport,
          panX: state.viewport.panX + action.dx,
          panY: state.viewport.panY + action.dy,
        },
      };

    case 'ZOOM': {
      const { zoom, panX, panY } = action;
      return {
        ...state,
        viewport: { zoom, panX, panY },
      };
    }

    case 'SET_ACTIVE_LAYER':
      return {
        ...state,
        activeLayerId: action.layerId,
      };

    case 'TOGGLE_GRID':
      return { ...state, showGrid: !state.showGrid };

    case 'TOGGLE_SNAP':
      return { ...state, snapEnabled: !state.snapEnabled };

    case 'SET_STATUS_MESSAGE':
      return { ...state, statusMessage: action.message };

    case 'CLEAR_STATUS_MESSAGE':
      if (!state.statusMessage) return state;
      return { ...state, statusMessage: null };

    default:
      return state;
  }
}

export function createInitialSketchEditorState(activeLayerId = null) {
  return {
    activeTool: SKETCH_TOOLS.SELECT,
    selectedId: null,
    selectedType: null,
    toolState: {},
    viewport: { panX: 400, panY: 300, zoom: DEFAULT_SKETCH_ZOOM },
    activeLayerId,
    showGrid: true,
    snapEnabled: true,
    statusMessage: null,
  };
}

export function SketchEditorProvider({ children, initialActiveLayerId = null }) {
  const [state, dispatch] = useReducer(
    sketchEditorReducer,
    initialActiveLayerId,
    createInitialSketchEditorState
  );

  return (
    <SketchEditorContext.Provider value={{ state, dispatch }}>
      {children}
    </SketchEditorContext.Provider>
  );
}

export function useSketchEditor() {
  const ctx = useContext(SketchEditorContext);
  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
  return { ...ctx.state, dispatch: ctx.dispatch };
}

import { SKETCH_GRID_MINOR, SKETCH_GRID_MAJOR, DEFAULT_CANVAS_WIDTH, DEFAULT_CANVAS_HEIGHT } from '../domain/defaults';

export default function GridRenderer() {
  return (
    <>
      <defs>
        <pattern
          id="sketch-grid-minor"
          width={SKETCH_GRID_MINOR}
          height={SKETCH_GRID_MINOR}
          patternUnits="userSpaceOnUse"
        >
          <path
            d={`M ${SKETCH_GRID_MINOR} 0 L 0 0 0 ${SKETCH_GRID_MINOR}`}
            fill="none"
            stroke="var(--color-grid-minor)"
            strokeWidth={1}
            vectorEffect="non-scaling-stroke"
          />
        </pattern>
        <pattern
          id="sketch-grid-major"
          width={SKETCH_GRID_MAJOR}
          height={SKETCH_GRID_MAJOR}
          patternUnits="userSpaceOnUse"
        >
          <rect
            width={SKETCH_GRID_MAJOR}
            height={SKETCH_GRID_MAJOR}
            fill="url(#sketch-grid-minor)"
          />
          <path
            d={`M ${SKETCH_GRID_MAJOR} 0 L 0 0 0 ${SKETCH_GRID_MAJOR}`}
            fill="none"
            stroke="var(--color-grid-major)"
            strokeWidth={2}
            vectorEffect="non-scaling-stroke"
          />
        </pattern>
      </defs>
      <rect
        x={-100000}
        y={-100000}
        width={DEFAULT_CANVAS_WIDTH + 200000}
        height={DEFAULT_CANVAS_HEIGHT + 200000}
        fill="url(#sketch-grid-major)"
        style={{ pointerEvents: 'none' }}
      />
    </>
  );
}

function RectShape({ shape }) {
  return (
    <rect
      x={shape.x}
      y={shape.y}
      width={shape.width}
      height={shape.height}
      fill={shape.fill}
      stroke={shape.stroke}
      strokeWidth={shape.strokeWidth}
      transform={shape.rotation ? `rotate(${shape.rotation} ${shape.x + shape.width / 2} ${shape.y + shape.height / 2})` : undefined}
    />
  );
}

function EllipseShape({ shape }) {
  const cx = shape.x + shape.width / 2;
  const cy = shape.y + shape.height / 2;
  const rx = Math.abs(shape.width) / 2;
  const ry = Math.abs(shape.height) / 2;

  return (
    <ellipse
      cx={cx}
      cy={cy}
      rx={rx}
      ry={ry}
      fill={shape.fill}
      stroke={shape.stroke}
      strokeWidth={shape.strokeWidth}
      transform={shape.rotation ? `rotate(${shape.rotation} ${cx} ${cy})` : undefined}
    />
  );
}

function LineShape({ shape }) {
  const points = shape.points;
  if (points.length < 2) return null;

  return (
    <line
      x1={points[0].x}
      y1={points[0].y}
      x2={points[1].x}
      y2={points[1].y}
      stroke={shape.stroke}
      strokeWidth={shape.strokeWidth}
      strokeLinecap="round"
    />
  );
}

function PathShape({ shape }) {
  const points = shape.points;
  if (points.length < 2) return null;

  const d = points.reduce((acc, pt, i) => {
    if (i === 0) return `M ${pt.x} ${pt.y}`;
    return `${acc} L ${pt.x} ${pt.y}`;
  }, '');

  return (
    <path
      d={d}
      fill={shape.fill}
      stroke={shape.stroke}
      strokeWidth={shape.strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
    />
  );
}

const shapeComponents = {
  rect: RectShape,
  ellipse: EllipseShape,
  line: LineShape,
  path: PathShape,
};

export default function ShapeRenderer({ shape, isSelected = false, zoom = 1 }) {
  const Component = shapeComponents[shape.type];
  if (!Component) return null;

  return (
    <g data-shape-id={shape.id}>
      <Component shape={shape} />
      {isSelected && (
        <rect
          x={shape.x - 4 / zoom}
          y={shape.y - 4 / zoom}
          width={(shape.width || 0) + 8 / zoom}
          height={(shape.height || 0) + 8 / zoom}
          fill="none"
          stroke="var(--color-workspace-sketch, #B8860B)"
          strokeWidth={1.5 / zoom}
          strokeDasharray={`${4 / zoom} ${3 / zoom}`}
          style={{ pointerEvents: 'none' }}
        />
      )}
    </g>
  );
}

import { useRef, useCallback, useEffect, useState } from 'react';
import { useSketch } from '../app/SketchProvider';
import { useSketchEditor } from '../app/SketchEditorProvider';
import { SKETCH_MIN_ZOOM, SKETCH_MAX_ZOOM, SKETCH_ZOOM_FACTOR } from '../domain/defaults';
import { SKETCH_TOOL_SHORTCUTS } from '../editor/tools';
import { createSketchSelectHandler } from '../editor/handlers/selectHandler';
import { createRectangleHandler } from '../editor/handlers/rectangleHandler';
import { createLineHandler } from '../editor/handlers/lineHandler';
import GridRenderer from './GridRenderer';
import ShapeRenderer from './ShapeRenderer';
import styles from './SketchCanvas.module.css';

function screenToModel(screenX, screenY, viewport, svgRect) {
  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
  return { x, y };
}

function useSketchTool() {
  const { dispatch: sketchDispatch, getLayer } = useSketch();
  const {
    activeTool, viewport, snapEnabled, selectedId, selectedType,
    toolState, activeLayerId, dispatch: editorDispatch,
  } = useSketchEditor();

  const ctx = {
    dispatch: sketchDispatch,
    editorDispatch,
    getLayer,
    activeLayerId,
    viewport,
    snapEnabled,
    selectedId,
    selectedType,
  };

  switch (activeTool) {
    case 'rectangle':
      return createRectangleHandler(ctx);
    case 'line':
      return createLineHandler(ctx);
    case 'select':
    default:
      return createSketchSelectHandler(ctx);
  }
}

export default function SketchCanvas() {
  const svgRef = useRef(null);
  const isPanning = useRef(false);
  const lastPanPos = useRef({ x: 0, y: 0 });
  const spaceHeld = useRef(false);
  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });

  const { project } = useSketch();
  const {
    activeTool, selectedId, toolState,
    viewport, showGrid, activeLayerId, statusMessage,
    dispatch: editorDispatch,
  } = useSketchEditor();

  const tool = useSketchTool();

  const getModelPos = useCallback((e) => {
    const rect = svgRef.current.getBoundingClientRect();
    return screenToModel(e.clientX, e.clientY, viewport, rect);
  }, [viewport]);

  const handleMouseDown = useCallback((e) => {
    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
      isPanning.current = true;
      lastPanPos.current = { x: e.clientX, y: e.clientY };
      e.preventDefault();
      return;
    }

    const modelPos = getModelPos(e);
    tool.onMouseDown(modelPos, e, toolState);
  }, [getModelPos, tool, toolState]);

  const handleMouseMove = useCallback((e) => {
    if (isPanning.current) {
      const dx = e.clientX - lastPanPos.current.x;
      const dy = e.clientY - lastPanPos.current.y;
      editorDispatch({ type: 'PAN', dx, dy });
      lastPanPos.current = { x: e.clientX, y: e.clientY };
      return;
    }

    const modelPos = getModelPos(e);
    setCursorPos(modelPos);
    tool.onMouseMove(modelPos, e, toolState, selectedId);
  }, [getModelPos, tool, toolState, selectedId, editorDispatch]);

  const handleMouseUp = useCallback((e) => {
    if (isPanning.current) {
      isPanning.current = false;
      return;
    }

    const modelPos = getModelPos(e);
    tool.onMouseUp(modelPos, e, toolState);
  }, [getModelPos, tool, toolState]);

  const handleWheel = useCallback((e) => {
    e.preventDefault();
    const rect = svgRef.current.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const direction = e.deltaY < 0 ? 1 : -1;
    const factor = direction > 0 ? SKETCH_ZOOM_FACTOR : 1 / SKETCH_ZOOM_FACTOR;
    const newZoom = Math.max(SKETCH_MIN_ZOOM, Math.min(SKETCH_MAX_ZOOM, viewport.zoom * factor));

    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);

    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
  }, [viewport, editorDispatch]);

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;

      if (e.key === ' ') {
        spaceHeld.current = true;
        e.preventDefault();
        return;
      }

      if (e.key === 'Escape') {
        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
        return;
      }

      if (!e.ctrlKey && !e.metaKey) {
        const toolKey = SKETCH_TOOL_SHORTCUTS[e.key.toLowerCase()];
        if (toolKey) {
          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
          return;
        }
      }

      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
        tool.onKeyDown(e, toolState, selectedId);
        return;
      }

      tool.onKeyDown(e, toolState, selectedId);
    };

    const handleKeyUp = (e) => {
      if (e.key === ' ') {
        spaceHeld.current = false;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [editorDispatch, selectedId, tool, toolState]);

  // Prevent context menu & attach wheel listener
  useEffect(() => {
    const svg = svgRef.current;
    if (!svg) return;
    const prevent = (e) => e.preventDefault();
    svg.addEventListener('contextmenu', prevent);
    svg.addEventListener('wheel', handleWheel, { passive: false });
    return () => {
      svg.removeEventListener('contextmenu', prevent);
      svg.removeEventListener('wheel', handleWheel);
    };
  }, [handleWheel]);

  // Status message auto-clear
  useEffect(() => {
    if (!statusMessage) return undefined;
    const timer = window.setTimeout(() => {
      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
    }, 2500);
    return () => window.clearTimeout(timer);
  }, [statusMessage, editorDispatch]);

  const cursor = spaceHeld.current ? 'grab' : tool.getCursor(toolState);
  const zoomPercent = Math.round(viewport.zoom * 1000);

  // Collect all visible shapes with their layer IDs
  const visibleShapes = [];
  for (const layer of project.layers) {
    if (!layer.visible) continue;
    for (const shape of layer.shapes) {
      visibleShapes.push({ shape, layerId: layer.id });
    }
  }

  // Rectangle preview
  const rectPreview = activeTool === 'rectangle' && toolState.startPos && toolState.currentPos
    ? {
        x: Math.min(toolState.startPos.x, toolState.currentPos.x),
        y: Math.min(toolState.startPos.y, toolState.currentPos.y),
        width: Math.abs(toolState.currentPos.x - toolState.startPos.x),
        height: Math.abs(toolState.currentPos.y - toolState.startPos.y),
      }
    : null;

  // Line preview
  const linePreview = activeTool === 'line' && toolState.startPos && toolState.currentPos
    ? { start: toolState.startPos, end: toolState.currentPos }
    : null;

  return (
    <div className={styles.canvasContainer}>
      <svg
        ref={svgRef}
        className={styles.svg}
        style={{ cursor }}
        onPointerDown={handleMouseDown}
        onPointerMove={handleMouseMove}
        onPointerUp={handleMouseUp}
      >
        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
          {showGrid && <GridRenderer />}

          {/* Canvas boundary indicator */}
          <rect
            x={0}
            y={0}
            width={project.canvasWidth}
            height={project.canvasHeight}
            fill="none"
            stroke="var(--color-border)"
            strokeWidth={2}
            vectorEffect="non-scaling-stroke"
            strokeDasharray="8 4"
            style={{ pointerEvents: 'none' }}
          />

          {/* Rendered shapes */}
          {visibleShapes.map(({ shape }) => (
            <ShapeRenderer
              key={shape.id}
              shape={shape}
              isSelected={shape.id === selectedId}
              zoom={viewport.zoom}
            />
          ))}

          {/* Rectangle draw preview */}
          {rectPreview && (
            <rect
              x={rectPreview.x}
              y={rectPreview.y}
              width={rectPreview.width}
              height={rectPreview.height}
              fill="none"
              stroke="var(--color-workspace-sketch, #B8860B)"
              strokeWidth={2}
              vectorEffect="non-scaling-stroke"
              strokeDasharray="6 3"
              style={{ pointerEvents: 'none' }}
            />
          )}

          {/* Line draw preview */}
          {linePreview && (
            <line
              x1={linePreview.start.x}
              y1={linePreview.start.y}
              x2={linePreview.end.x}
              y2={linePreview.end.y}
              stroke="var(--color-workspace-sketch, #B8860B)"
              strokeWidth={2}
              vectorEffect="non-scaling-stroke"
              strokeDasharray="6 3"
              style={{ pointerEvents: 'none' }}
            />
          )}
        </g>
      </svg>

      {/* Status bar */}
      <div className={styles.statusBar} role="status" aria-live="polite">
        <span className={styles.statusCoords}>X: {Math.round(cursorPos.x)} mm</span>
        <span className={styles.statusCoords}>Y: {Math.round(cursorPos.y)} mm</span>
        <span className={styles.statusContext}>Zoom: {zoomPercent}%</span>
        <span className={styles.statusTool}>{activeTool}</span>
        {activeLayerId && (
          <span className={styles.statusContext}>
            Layer: {project.layers.find((l) => l.id === activeLayerId)?.name || 'Unknown'}
          </span>
        )}
      </div>

      {/* Toast notifications */}
      {statusMessage && (
        <div className={styles.toast}>
          {statusMessage}
          <div className={styles.toastProgress} />
        </div>
      )}
    </div>
  );
}

