    dispatch({
      type: 'LAYER_UPDATE',
      layer: { id: layer.id, locked: !layer.locked },
    });
  };

  const handleDeleteLayer = (e, layerId) => {
    e.stopPropagation();
    if (project.layers.length <= 1) return;
    dispatch({ type: 'LAYER_DELETE', layerId });

    // If we're deleting the active layer, switch to the first remaining layer
    if (activeLayerId === layerId) {
      const remaining = project.layers.find((l) => l.id !== layerId);
      if (remaining) {
        editorDispatch({ type: 'SET_ACTIVE_LAYER', layerId: remaining.id });
      }
    }
  };

  return (
    <div className={styles.sidebar}>
      <div className={styles.section}>
        <div className={styles.sectionHeaderRow}>
          <span className={styles.sectionTitle}>Layers</span>
          <span className={styles.count}>{project.layers.length}</span>
          <button
            className={styles.addBtn}
            onClick={handleAddLayer}
            aria-label="Add Layer"
            title="Add Layer"
          >
            +
          </button>
        </div>

        <div className={styles.layerList}>
          {project.layers.map((layer) => {
            const isActive = layer.id === activeLayerId;
            const shapeCount = layer.shapes.length;

            return (
              <div
                key={layer.id}
                className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
                onClick={() => handleSelectLayer(layer.id)}
                role="button"
                tabIndex={0}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    handleSelectLayer(layer.id);
                  }
                }}
              >
                <div className={styles.layerInfo}>
                  <span className={styles.layerName}>{layer.name}</span>
                  {shapeCount > 0 && (
                    <span className={styles.shapeCount}>{shapeCount}</span>
                  )}
                </div>
                <div className={styles.layerActions}>
                  <button
                    className={styles.layerActionBtn}
                    onClick={(e) => handleToggleVisibility(e, layer)}
                    aria-label={layer.visible ? 'Hide Layer' : 'Show Layer'}
                    title={layer.visible ? 'Hide Layer' : 'Show Layer'}
                  >
                    <EyeIcon visible={layer.visible} />
                  </button>
                  <button
                    className={styles.layerActionBtn}
                    onClick={(e) => handleToggleLock(e, layer)}
                    aria-label={layer.locked ? 'Unlock Layer' : 'Lock Layer'}
                    title={layer.locked ? 'Unlock Layer' : 'Lock Layer'}
                  >
                    <LockIcon locked={layer.locked} />
                  </button>
                  <button
                    className={styles.layerActionBtn}
                    onClick={(e) => handleDeleteLayer(e, layer.id)}
                    disabled={project.layers.length <= 1}
                    aria-label="Delete Layer"
                    title="Delete Layer"
                  >
                    <TrashIcon />
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

.sidebar {
  background: var(--color-panel-bg);
  border-right: 1px solid var(--color-border);
  overflow-y: auto;
  padding: var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.section {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.sectionHeaderRow {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 2px 4px;
  border-bottom: 1px solid var(--color-workspace-sketch, #B8860B);
  padding-bottom: 6px;
}

.sectionTitle {
  font-family: var(--font-heading);
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--color-text-primary);
}

.count {
  margin-left: auto;
  font-size: 10px;
  color: var(--color-workspace-sketch, #B8860B);
  background: rgba(184, 134, 11, 0.1);
  padding: 0 5px;
  border-radius: 10px;
  line-height: 18px;
  font-weight: 700;
}

.addBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border-radius: var(--radius-sm);
  color: var(--color-text-secondary);
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  background: transparent;
  border: none;
  transition: background var(--duration-fast), color var(--duration-fast);
  flex-shrink: 0;
}

.addBtn:hover {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-workspace-sketch, #B8860B);
}

.addBtn:active {
  transform: scale(0.92);
}

.layerList {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.layerItem {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 8px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: background var(--duration-fast);
  border: 1px solid transparent;
}

.layerItem:hover {
  background: rgba(0, 0, 0, 0.03);
}

.layerItemActive {
  background: rgba(184, 134, 11, 0.08);
  border-color: rgba(184, 134, 11, 0.2);
}

.layerItemActive:hover {
  background: rgba(184, 134, 11, 0.12);
}

.layerInfo {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
  flex: 1;
}

.layerName {
  font-family: var(--font-ui);
  font-size: 12px;
  font-weight: 500;
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.shapeCount {
  font-size: 10px;
  color: var(--color-text-tertiary);
  background: rgba(0, 0, 0, 0.04);
  padding: 0 4px;
  border-radius: 8px;
  line-height: 16px;
  flex-shrink: 0;
}

.layerActions {
  display: flex;
  align-items: center;
  gap: 2px;
  flex-shrink: 0;
  opacity: 0.5;
  transition: opacity var(--duration-fast);
}

.layerItem:hover .layerActions {
  opacity: 1;
}

.layerItemActive .layerActions {
  opacity: 0.8;
}

.layerActionBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  border-radius: var(--radius-sm);
  background: transparent;
  border: none;
  color: var(--color-text-secondary);
  cursor: pointer;
  transition: background var(--duration-fast), color var(--duration-fast);
}

.layerActionBtn:hover {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-text-primary);
}

.layerActionBtn:active {
  transform: scale(0.9);
}

.layerActionBtn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

.layerActionBtn:disabled:hover {
  background: transparent;
  color: var(--color-text-secondary);
}

.layerActionIcon {
  width: 14px;
  height: 14px;
  display: block;
}

import { useMemo } from 'react';
import { SketchProvider, useSketch } from './app/SketchProvider';
import { SketchEditorProvider } from './app/SketchEditorProvider';
import SketchToolbar from './ui/SketchToolbar';
import SketchSidebar from './ui/SketchSidebar';
import SketchCanvas from './renderers/SketchCanvas';
import styles from './SketchWorkspace.module.css';

function SketchInner() {
  const { project } = useSketch();
  const initialLayerId = useMemo(
    () => project.layers[0]?.id || null,
    // Only compute once on mount
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  return (
    <SketchEditorProvider initialActiveLayerId={initialLayerId}>
      <div className={styles.layout}>
        <div className={styles.toolbar}>
          <SketchToolbar />
        </div>
        <div className={styles.sidebar}>
          <SketchSidebar />
        </div>
        <div className={styles.canvas}>
          <SketchCanvas />
        </div>
      </div>
    </SketchEditorProvider>
  );
}

export default function SketchWorkspace({ initialProject }) {
  return (
    <div className="editorRoot">
      <SketchProvider initialProject={initialProject}>
        <SketchInner />
      </SketchProvider>
    </div>
  );
}

.layout {
  display: grid;
  grid-template-rows: var(--toolbar-height, 52px) 1fr;
  grid-template-columns: var(--sidebar-width, 240px) 1fr;
  grid-template-areas:
    "toolbar toolbar"
    "sidebar canvas";
  height: 100%;
  width: 100%;
}

.toolbar {
  grid-area: toolbar;
  position: relative;
  z-index: 10;
}

.sidebar {
  grid-area: sidebar;
  min-height: 0;
  overflow-y: auto;
}

.canvas {
  grid-area: canvas;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  box-shadow: inset 1px 0 3px rgba(0, 0, 0, 0.04), inset -1px 0 3px rgba(0, 0, 0, 0.04);
}

@media (max-width: 768px) {
  .layout {
    grid-template-columns: 0px 1fr;
  }
  .sidebar {
    position: fixed;
    top: var(--toolbar-height, 52px);
    left: 0;
    bottom: 0;
    z-index: 20;
    width: var(--sidebar-width, 240px);
    background: var(--color-panel-bg);
    box-shadow: var(--shadow-floating);
    transform: translateX(-100%);
    transition: transform var(--duration-layout) var(--ease-out);
  }
}

